(()=>{'use strict';
const $=s=>document.querySelector(s);
let overlay,card,bar,pct,title,detail,stage,active=false,timer=null,hideTimer=null,readPct=0,successAt=0;
function css(){if($('#uploadProgressStyle'))return;const st=document.createElement('style');st.id='uploadProgressStyle';st.textContent=`.upgOverlay{position:fixed;inset:0;background:rgba(15,23,42,.48);backdrop-filter:blur(3px);z-index:200;display:none;align-items:center;justify-content:center;padding:16px}.upgOverlay.on{display:flex}.upgCard{width:min(92vw,430px);background:#fff;border:1px solid #d1d5db;border-radius:22px;box-shadow:0 24px 80px rgba(0,0,0,.35);overflow:hidden;transform:scale(.96);opacity:0;transition:.18s ease;position:relative}.upgOverlay.on .upgCard{transform:scale(1);opacity:1}.upgClose{position:absolute;right:10px;top:10px;width:30px;height:30px;border:0;border-radius:999px;background:#f1f5f9;color:#334155;font-weight:950}.upgTop{padding:18px 18px 8px;text-align:center}.upgIcon{width:58px;height:58px;border-radius:999px;margin:0 auto 10px;background:conic-gradient(from 0deg,#087b34,#22c55e,#86efac,#087b34);display:grid;place-items:center;animation:upgSpin 1.1s linear infinite}.upgIcon i{width:42px;height:42px;border-radius:999px;background:#fff;display:grid;place-items:center;font-style:normal;font-weight:950;color:#087b34}.upgTitle{font-weight:950;color:#111827;font-size:18px}.upgPct{font-weight:950;color:#087b34;font-size:42px;line-height:1.05;margin-top:6px;font-variant-numeric:tabular-nums}.upgDetail{padding:0 18px 12px;color:#4b5563;font-size:13px;line-height:1.45;text-align:center;min-height:40px}.upgTrack{height:14px;background:#e5e7eb;margin:0 18px 12px;border-radius:999px;overflow:hidden;position:relative}.upgBar{height:100%;width:0%;background:linear-gradient(90deg,#087b34,#22c55e,#86efac,#22c55e);background-size:220% 100%;transition:width .12s linear;animation:upgMove .8s linear infinite}.upgTrack:after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent,rgba(255,255,255,.55),transparent);transform:translateX(-100%);animation:upgSweep 1.25s ease-in-out infinite}.upgIndeterminate .upgBar{width:100%!important;opacity:.92;animation:upgMove .55s linear infinite}.upgIndeterminate .upgTrack:after{animation:upgSweep .9s ease-in-out infinite}.upgStage{display:grid;grid-template-columns:repeat(4,1fr);gap:0;border-top:1px solid #eef2f7;background:#f8fafc}.upgStage div{font-size:11px;text-align:center;padding:9px 4px;color:#6b7280;font-weight:900;position:relative}.upgStage div.on{color:#087b34;background:#ecfdf5}.upgStage div.on:before{content:'';position:absolute;left:50%;top:3px;width:6px;height:6px;border-radius:999px;background:#22c55e;transform:translateX(-50%);animation:upgPulse .75s ease-in-out infinite}.upgErr .upgBar{background:#dc2626;animation:none}.upgErr .upgPct{color:#dc2626}.upgErr .upgIcon{background:#dc2626;animation:none}.upgErr .upgIcon i{color:#dc2626}@keyframes upgSpin{to{transform:rotate(360deg)}}@keyframes upgMove{0%{background-position:0 0}100%{background-position:220% 0}}@keyframes upgSweep{0%{transform:translateX(-110%)}55%,100%{transform:translateX(110%)}}@keyframes upgPulse{0%,100%{transform:translateX(-50%) scale(.8);opacity:.65}50%{transform:translateX(-50%) scale(1.45);opacity:1}}@media(max-width:420px){.upgCard{width:94vw;border-radius:18px}.upgPct{font-size:36px}.upgTop{padding-top:16px}}`;document.head.appendChild(st)}
function ui(){css();if(overlay)return;overlay=document.createElement('div');overlay.className='upgOverlay';overlay.innerHTML='<div class="upgCard"><button class="upgClose" type="button">×</button><div class="upgTop"><div class="upgIcon"><i>↑</i></div><div class="upgTitle">กำลังอ่านไฟล์</div><div class="upgPct">0%</div></div><div class="upgDetail">รอเลือกไฟล์</div><div class="upgTrack"><div class="upgBar"></div></div><div class="upgStage"><div data-s="read">อ่านไฟล์จริง</div><div data-s="parse">ประมวลผล</div><div data-s="calc">รวมยอด</div><div data-s="done">เสร็จ</div></div></div>';document.body.appendChild(overlay);card=overlay.querySelector('.upgCard');bar=overlay.querySelector('.upgBar');pct=overlay.querySelector('.upgPct');title=overlay.querySelector('.upgTitle');detail=overlay.querySelector('.upgDetail');stage=overlay.querySelector('.upgStage');overlay.querySelector('.upgClose').onclick=forceHide}
function setStage(s){stage.querySelectorAll('div').forEach(x=>x.classList.toggle('on',x.dataset.s===s))}
function forceHide(){clearTimeout(hideTimer);clearInterval(timer);active=false;if(!overlay)return;overlay.classList.remove('on');overlay.style.display='none';setTimeout(()=>{if(overlay)overlay.style.display=''},120)}
function open(){ui();clearTimeout(hideTimer);clearInterval(timer);overlay.style.display='';overlay.classList.add('on');card.classList.remove('upgErr','upgIndeterminate');active=true;readPct=0;successAt=0;bar.style.width='0%';pct.textContent='0%';title.textContent='กำลังอ่านไฟล์';detail.textContent='เริ่มอ่านไฟล์จากเครื่อง';setStage('read')}
function setRead(p,t,d){ui();readPct=Math.max(readPct,Math.min(100,Math.round(p)));card.classList.remove('upgIndeterminate');bar.style.width=readPct+'%';pct.textContent=readPct+'%';if(t)title.textContent=t;if(d)detail.textContent=d;setStage('read')}
function setBusy(){ui();card.classList.add('upgIndeterminate');pct.textContent='กำลังทำงาน';title.textContent='กำลังประมวลผลไฟล์';detail.textContent='ระบบกำลังแปลงข้อมูลจริง ไม่แสดงเปอร์เซ็นต์หลอก';setStage('parse');const start=Date.now();clearInterval(timer);timer=setInterval(()=>{if(!active)return clearInterval(timer);const sec=Math.max(1,Math.floor((Date.now()-start)/1000));const dots='.'.repeat(sec%4);detail.textContent=`ระบบกำลังแปลงข้อมูลจริง${dots} ใช้เวลา ${sec} วินาที`;if(sec>2)setStage('calc')},300)}
function success(){ui();clearInterval(timer);card.classList.remove('upgIndeterminate');bar.style.width='100%';pct.textContent='100%';title.textContent='อ่านไฟล์สำเร็จ';detail.textContent='ข้อมูลแสดงในตารางแล้ว';setStage('done');active=false;successAt=Date.now();hideTimer=setTimeout(forceHide,450)}
function fail(msg){ui();clearInterval(timer);card.classList.remove('upgIndeterminate');card.classList.add('upgErr');bar.style.width='100%';pct.textContent='ผิดพลาด';title.textContent='อ่านไฟล์ไม่สำเร็จ';detail.textContent=msg||'เกิดข้อผิดพลาด';setStage('done');active=false;hideTimer=setTimeout(forceHide,3500)}
function readWithProgress(file){return new Promise(resolve=>{try{const r=new FileReader();r.onprogress=e=>{if(!e.lengthComputable){setRead(1,'กำลังอ่านไฟล์',`${file.name} · กำลังอ่านจากเครื่อง`);return}setRead((e.loaded/e.total)*100,'กำลังอ่านไฟล์',`${file.name} · ${Math.round(e.loaded/1024).toLocaleString('th-TH')} / ${Math.round(e.total/1024).toLocaleString('th-TH')} KB`)};r.onload=()=>{setRead(100,'อ่านไฟล์จากเครื่องเสร็จ','กำลังส่งให้ระบบประมวลผล');resolve()};r.onerror=()=>{fail('อ่านไฟล์จากเครื่องไม่สำเร็จ');resolve()};r.readAsArrayBuffer(file)}catch{resolve()}})}
function bind(){ui();const file=$('#file');if(file&&!file.dataset.upgBound){file.dataset.upgBound='1';file.addEventListener('change',async e=>{const f=e.target.files&&e.target.files[0];if(!f)return;open();setRead(1,'เลือกไฟล์แล้ว',`${f.name} · ${(f.size/1024/1024).toFixed(2)} MB`);await readWithProgress(f);setBusy()},true)}const msg=$('#msg');if(msg&&!msg.dataset.upgObs){msg.dataset.upgObs='1';new MutationObserver(()=>{const s=(msg.textContent||'').trim();if(!overlay||!overlay.classList.contains('on'))return;if(/อ่านสำเร็จ|พร้อมใช้งาน|กู้คืน Autosave/.test(s)){success()}else if(/ผิดพลาด|ไม่พบข้อมูล|โหลดไม่สำเร็จ|error/i.test(s)){fail(s)}}).observe(msg,{childList:true,subtree:true,characterData:true})}setInterval(()=>{if(overlay&&overlay.classList.contains('on')&&successAt&&Date.now()-successAt>700)forceHide()},250)}
document.addEventListener('DOMContentLoaded',()=>{bind();setTimeout(bind,500);new MutationObserver(()=>setTimeout(bind,0)).observe(document.documentElement,{childList:true,subtree:true})});
})();